       //OPTION: 2
        if (isLoading || newValue === '') {
            return;
        }

        var startVal = g_form.getValue('start_date_time');
        var endVal = g_form.getValue('end_date_time');

        if (!startVal || !endVal) {
            return;
        }

        var start = new Date(startVal);
        var end = new Date(endVal);

        if (end < start) {
            g_form.addErrorMessage('End date/time should not be before the Start date/time');
            g_form.setValue('end_date_time', '');
            return;
        }

